diff --git a/src/discount/apply.ts b/src/discount/apply.ts
index 1000aaa..2000bbb 100644
--- a/src/discount/apply.ts
+++ b/src/discount/apply.ts
@@ -1,6 +1,18 @@
 import { Order } from './types';

 export function totalAfterDiscount(order: Order): number {
   return order.subtotal - order.discount;
 }
+
+/**
+ * Apply a stacked coupon on top of the existing discount.
+ * Public API used by the checkout route.
+ */
+export function applyStackedCoupon(order: Order, coupon: { percent: number }): Order {
+  const extra = order.subtotal * (coupon.percent / 100);
+  return {
+    ...order,
+    discount: order.discount + extra,
+  };
+}

